class LUPrefix:
    def __init__(self, n: int):
        self.seen = [False] * (n + 2)
        self.frontier = 0
    def upload(self, video: int) -> None:
        self.seen[video] = True
        while self.seen[self.frontier + 1]:
            self.frontier += 1
    def longest(self) -> int:
        return self.frontier

