class LUPrefix {
    constructor(n) {
        this.seen = new Uint8Array(n + 2);
        this.frontier = 0;
    }
    upload(video) {
        this.seen[video] = 1;
        while (this.seen[this.frontier + 1]) this.frontier++;
    }
    longest() {
        return this.frontier;
    }
}
